import{_ as t,o as r,c as e,a2 as o}from"./chunks/framework.DIMps2S2.js";const u=JSON.parse('{"title":"我的卡券","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"rewards/rewards-mall/my-coupons.md","filePath":"zh-CN/rewards/rewards-mall/my-coupons.md"}'),l={name:"rewards/rewards-mall/my-coupons.md"};function d(s,a,i,n,h,c){return r(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="我的卡券" tabindex="-1">我的卡券 <a class="header-anchor" href="#我的卡券" aria-label="Permalink to &quot;我的卡券&quot;">​</a></h1><p>「我的卡券」页面用于查看和管理账户内所有持有的卡券。入口在「我的」→「我的卡券」，或「我的」快捷功能栏。</p><h2 id="分类-tab" tabindex="-1">分类 Tab <a class="header-anchor" href="#分类-tab" aria-label="Permalink to &quot;分类 Tab&quot;">​</a></h2><p>页面顶部按卡券类型分 Tab 筛选：</p><p><strong>全部 / 行情卡 / 免佣卡 / 打新卡 / 现金卡 / 股票卡 / 抵扣卡</strong></p><h2 id="卡券列表" tabindex="-1">卡券列表 <a class="header-anchor" href="#卡券列表" aria-label="Permalink to &quot;卡券列表&quot;">​</a></h2><p>每张卡券显示：</p><ul><li><strong>卡券名称</strong>（如「HKD 0.1 股票现金卡」「港股终生免佣」「终生半价咖啡优惠券」）</li><li><strong>适用范围标签</strong>（如「股票、轮证、ETF · 仅支持长桥综合账户」「适用 US、HK 市场」）</li><li><strong>有效期</strong>（如「2025/09/29 - 永久」「2025/12/05 09:18 - 2026/01/04 09:18」）</li><li><strong>状态标签</strong>：使用中 / 待兑现 / 即将到期</li><li><strong>操作按钮</strong>：「立即使用」（需手动激活的卡券显示此按钮）</li></ul><h2 id="卡券状态说明" tabindex="-1">卡券状态说明 <a class="header-anchor" href="#卡券状态说明" aria-label="Permalink to &quot;卡券状态说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>状态</th><th>含义</th></tr></thead><tbody><tr><td>使用中</td><td>已激活，当前有效（如终生免佣）</td></tr><tr><td>待兑现</td><td>已发放，等待条件触发后兑现</td></tr><tr><td>即将到期</td><td>有效期不足 7 天，建议尽快使用</td></tr></tbody></table><p>免佣卡、行情卡等自动激活类卡券发放后直接生效，无需手动操作，不显示「立即使用」按钮；股票卡、现金卡等需手动激活的卡券才显示该按钮。卡券有效期由发放规则决定，激活后不影响到期时间，请在截止日期前完成使用。使用后可在「全部」Tab 查看最新状态，并在「我的」→「奖励记录」查看对应奖励发放流水。</p><h2 id="隐藏已失效卡券" tabindex="-1">隐藏已失效卡券 <a class="header-anchor" href="#隐藏已失效卡券" aria-label="Permalink to &quot;隐藏已失效卡券&quot;">​</a></h2><p>页面底部「隐藏已使用/已失效卡券」开关，默认开启。关闭后可查看所有历史卡券记录。</p><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/rewards">活动与奖励</a></li></ul>',15)])])}const b=t(l,[["render",d]]);export{u as __pageData,b as default};
